package jetbrains.mps.baseLanguage.unitTest.execution.client;

/*Generated by MPS */

import jetbrains.mps.components.ComponentHost;
import java.util.Optional;
import jetbrains.mps.baseLanguage.unitTest.platform.TestDescriptor;
import org.jetbrains.annotations.NotNull;
import org.jetbrains.mps.openapi.model.SNode;
import jetbrains.mps.baseLanguage.unitTest.platform.TestDiscoveryRequest;
import jetbrains.mps.baseLanguage.unitTest.platform.TestPlatform;
import org.jetbrains.annotations.Nullable;
import jetbrains.mps.baseLanguage.unitTest.platform.TestDiscoveryParticipant;
import org.jetbrains.mps.openapi.language.SAbstractConcept;
import jetbrains.mps.lang.smodel.generator.smodelAdapter.SNodeOperations;
import jetbrains.mps.internal.collections.runtime.Sequence;

/**
 * In UI and some other places of [execution], we use ITestNodeWrapper, which used to be a test-aware facade of a node, and is essentially present day TestDecriptor.
 * We shall stick to TestDescriptor and eliminate ITestNodeWrapper altogether
 */
public final class TestNodeWrapperFactory {
  private final ComponentHost myPlatform;

  public TestNodeWrapperFactory(ComponentHost mpsPlatform) {
    myPlatform = mpsPlatform;
  }

  /**
   * Unless there's true need for ITestNodeWrapper (legacy compatibility API), stick to TestDescriptor
   */
  public Optional<TestDescriptor> findTestDescriptor(@NotNull SNode node) {
    TestDiscoveryRequest request = new TestDiscoveryRequest(new TestDescriptor());
    TestPlatform component = myPlatform.findComponent(TestPlatform.class);
    return (component != null ? component.getAggregateDiscoveryParticipant().discover(node, request) : Optional.empty());
  }

  @Nullable
  public ITestNodeWrapper tryToWrap(@NotNull SNode node) {
    //  here we used to check module.compileInMPS, but I see no reason to perform the check at this level
    // (either TestDiscoveryParticipant shall bother, or external code that tries to discover tests may limit set of modules/models being inspected)
    Optional<TestDescriptor> td = findTestDescriptor(node);
    return td.map(TestDescriptorWrapper::new).orElse(null);
  }

  public SNode findWrappableAncestor(SNode source, boolean isRoot) {
    TestDiscoveryParticipant tdp = myPlatform.findComponent(TestPlatform.class).getAggregateDiscoveryParticipant();
    Iterable<SAbstractConcept> concepts = tdp.sourceConcepts();
    return SNodeOperations.getNodeAncestorWhereConceptInList(source, Sequence.fromIterable(concepts).toGenericArray(SAbstractConcept.class), true, isRoot);
  }

}
